// MARK: - Realtime Quotes (WebSocket)

protocol QuotesStreamDelegate: AnyObject {
    func quotesStreamDidConnect()
    func quotesStreamDidDisconnect(_ error: Error?)
    func quotesStreamDidReceive(_ quote: StockQuote)
}

final class QuotesStream: NSObject {
    static let shared = QuotesStream()

    private var task: URLSessionWebSocketTask?
    private lazy var session: URLSession = {
        URLSession(configuration: .default, delegate: self, delegateQueue: nil)
    }()

    weak var delegate: QuotesStreamDelegate?

    private var isConnected = false
    private var subscribed: Set<String> = []
    private var reconnectTask: Task<Void, Never>?

    var socketURL: URL = URL(string: "wss://stream.example.com/quotes")!

    func connect() {
        guard task == nil else { return }
        var req = URLRequest(url: socketURL)
        if let token = SessionManager.shared.accessToken {
            req.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        let ws = session.webSocketTask(with: req)
        task = ws
        ws.resume()
        isConnected = true
        delegate?.quotesStreamDidConnect()
        listen()
        heartbeat()
        if !subscribed.isEmpty {
            sendSubscribe(Array(subscribed))
        }
    }

    func disconnect() {
        reconnectTask?.cancel()
        reconnectTask = nil
        isConnected = false
        task?.cancel(with: .goingAway, reason: nil)
        task = nil
        delegate?.quotesStreamDidDisconnect(nil)
    }

    func subscribe(symbols: [String]) {
        let upper = symbols.map { $0.uppercased() }
        upper.forEach { subscribed.insert($0) }
        if isConnected {
            sendSubscribe(upper)
        } else {
            connect()
        }
    }

    func unsubscribe(symbols: [String]) {
        let upper = symbols.map { $0.uppercased() }
        upper.forEach { subscribed.remove($0) }
        if isConnected {
            sendUnsubscribe(upper)
        }
    }

    private func sendSubscribe(_ symbols: [String]) {
        let payload: [String: Any] = ["type": "subscribe", "symbols": symbols]
        sendJSON(payload)
    }

    private func sendUnsubscribe(_ symbols: [String]) {
        let payload: [String: Any] = ["type": "unsubscribe", "symbols": symbols]
        sendJSON(payload)
    }

    private func sendJSON(_ obj: [String: Any]) {
        guard let data = try? JSONSerialization.data(withJSONObject: obj) else { return }
        task?.send(.data(data)) { _ in }
    }

    private func listen() {
        task?.receive { [weak self] result in
            guard let self else { return }
            switch result {
            case .failure(let error):
                self.isConnected = false
                self.delegate?.quotesStreamDidDisconnect(error)
                self.scheduleReconnect()
            case .success(let message):
                self.handle(message)
                self.listen()
            }
        }
    }

    private func handle(_ message: URLSessionWebSocketTask.Message) {
        let data: Data?
        switch message {
        case .data(let d): data = d
        case .string(let s): data = Data(s.utf8)
        @unknown default: data = nil
        }
        guard let data else { return }
        if let quote = try? JSONDecoder.api.decode(StockQuote.self, from: data) {
            delegate?.quotesStreamDidReceive(quote)
        }
    }

    private func scheduleReconnect() {
        guard reconnectTask == nil else { return }
        reconnectTask = Task { [weak self] in
            guard let self else { return }
            try? await Task.sleep(nanoseconds: 1_000_000_000)
            guard !Task.isCancelled else { return }
            self.task = nil
            self.connect()
            self.reconnectTask = nil
        }
    }

    private func heartbeat() {
        Task { [weak self] in
            while let self, self.isConnected, !Task.isCancelled {
                try? await Task.sleep(nanoseconds: 15_000_000_000)
                guard self.isConnected else { break }
                self.task?.sendPing { [weak self] error in
                    guard let self else { return }
                    if let error = error {
                        self.isConnected = false
                        self.delegate?.quotesStreamDidDisconnect(error)
                        self.scheduleReconnect()
                    }
                }
            }
        }
    }
}

extension QuotesStream: URLSessionWebSocketDelegate {
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didOpenWithProtocol protocol: String?) {
        isConnected = true
        delegate?.quotesStreamDidConnect()
        if !subscribed.isEmpty {
            sendSubscribe(Array(subscribed))
        }
    }

    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didCloseWith closeCode: URLSessionWebSocketTask.CloseCode, reason: Data?) {
        isConnected = false
        delegate?.quotesStreamDidDisconnect(nil)
        scheduleReconnect()
    }
}

// MARK: - Trading / Portfolio Service

final class TradingService {
    static let shared = TradingService()
    private init() {}

    func getPortfolio() async throws -> PortfolioSnapshot {
        try await APIClient.shared.request("GET", path: "/v1/portfolio", response: PortfolioSnapshot.self)
    }

    func getPositions() async throws -> [Position] {
        try await APIClient.shared.request("GET", path: "/v1/positions", response: [Position].self)
    }

    func getQuote(symbol: String) async throws -> StockQuote {
        try await APIClient.shared.request("GET", path: "/v1/quotes/\(symbol.uppercased())", response: StockQuote.self)
    }

    func placeOrder(_ req: OrderRequest) async throws -> OrderResponse {
        try await APIClient.shared.request("POST", path: "/v1/orders", body: req, response: OrderResponse.self)
    }

    func cancelOrder(orderId: String) async throws -> OrderResponse {
        try await APIClient.shared.request("POST", path: "/v1/orders/\(orderId)/cancel", response: OrderResponse.self)
    }

    func listFills(limit: Int = 50) async throws -> [Fill] {
        try await APIClient.shared.request("GET", path: "/v1/fills", query: [URLQueryItem(name: "limit", value: "\(limit)")], response: [Fill].self)
    }
}

// MARK: - Local Portfolio Store (fast UX fallback)

final class PortfolioStore {
    static let shared = PortfolioStore()

    private(set) var snapshot = PortfolioSnapshot(cash: 0, positions: [], dayPnL: 0)
    private let queue = DispatchQueue(label: "portfolio.store", qos: .userInitiated)

    func updateQuote(_ quote: StockQuote) {
        queue.async {
            var positions = self.snapshot.positions
            if let idx = positions.firstIndex(where: { $0.symbol == quote.symbol }) {
                var p = positions[idx]
                p.marketPrice = quote.last
                positions[idx] = p
                self.snapshot.positions = positions
            }
        }
    }
}

// MARK: - View Models

@MainActor
final class AppViewModel: NSObject, QuotesStreamDelegate {
    static let shared = AppViewModel()

    private(set) var portfolio: PortfolioSnapshot = .init(cash: 0, positions: [], dayPnL: 0) {
        didSet { onPortfolio?(portfolio) }
    }
    private(set) var quotes: [String: StockQuote] = [:] {
        didSet { onQuotes?(quotes) }
    }

    var onPortfolio: ((PortfolioSnapshot) -> Void)?
    var onQuotes: (([String: StockQuote]) -> Void)?
    var onToast: ((String) -> Void)?

    private var refreshTask: Task<Void, Never>?

    override private init() {
        super.init()
        QuotesStream.shared.delegate = self
    }

    func start() {
        refreshTask?.cancel()
        refreshTask = Task { [weak self] in
            guard let self else { return }
            await self.refreshPortfolio()
            while !Task.isCancelled {
                try? await Task.sleep(nanoseconds: 10_000_000_000)
                await self.refreshPortfolio(silent: true)
            }
        }
    }

    func stop() {
        refreshTask?.cancel()
        refreshTask = nil
        QuotesStream.shared.disconnect()
    }

    func refreshPortfolio(silent: Bool = false) async {
        do {
            let p = try await TradingService.shared.getPortfolio()
            self.portfolio = p
            let symbols = p.positions.map { $0.symbol }
            if !symbols.isEmpty {
                QuotesStream.shared.subscribe(symbols: symbols)
            }
        } catch {
            if !silent {
                self.onToast?(error.localizedDescription)
            }
        }
    }

    func submitOrder(symbol: String, side: OrderSide, type: OrderType, quantity: Decimal, limitPrice: Decimal?, tif: TimeInForce) async {
        let sym = symbol.uppercased().trimmingCharacters(in: .whitespacesAndNewlines)
        guard !sym.isEmpty else { onToast?("Enter a symbol."); return }
        guard quantity > 0 else { onToast?("Quantity must be greater than 0."); return }
        if type == .limit, (limitPrice ?? 0) <= 0 { onToast?("Limit price must be greater than 0."); return }

        let req = OrderRequest(
            symbol: sym,
            side: side,
            type: type,
            quantity: quantity.rounded(6),
            limitPrice: limitPrice?.rounded(6),
            timeInForce: tif,
            clientOrderId: UUID().uuidString
        )

        do {
            let res = try await TradingService.shared.placeOrder(req)
            switch res.status {
            case .accepted, .pending:
                onToast?("Order submitted (\(res.status.rawValue)).")
            case .filled:
                onToast?("Order filled.")
            case .rejected:
                onToast?("Order rejected\(res.message.map { ": \($0)" } ?? ".")")
            default:
                onToast?("Order status: \(res.status.rawValue).")
            }
            await refreshPortfolio(silent: true)
        } catch {
            onToast?(error.localizedDescription)
        }
    }

    // MARK: QuotesStreamDelegate
    func quotesStreamDidConnect() {}

    func quotesStreamDidDisconnect(_ error: Error?) {
        if let error { onToast?("Live quotes disconnected: \(error.localizedDescription)") }
    }

    func quotesStreamDidReceive(_ quote: StockQuote) {
        quotes[quote.symbol] = quote
        var p = portfolio
        if let idx = p.positions.firstIndex(where: { $0.symbol == quote.symbol }) {
            var pos = p.positions[idx]
            pos.marketPrice = quote.last
            p.positions[idx] = pos
            portfolio = p
        }
    }
}

// MARK: - UI Components

final class ToastView: UIView {
    private let label = UILabel()
    private var hideWorkItem: DispatchWorkItem?

    override init(frame: CGRect) {
        super.init(frame: frame)
        backgroundColor = UIColor.label.withAlphaComponent(0.92)
        layer.cornerRadius = 12
        layer.masksToBounds = true

        label.textColor = .systemBackground
        label.numberOfLines = 0
        label.font = UIFont.preferredFont(forTextStyle: .subheadline)
        label.adjustsFontForContentSizeCategory = true

        addSubview(label)
        label.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            label.topAnchor.constraint(equalTo: topAnchor, constant: 10),
            label.bottomAnchor.constraint(equalTo: bottomAnchor, constant: -10),
            label.leadingAnchor.constraint(equalTo: leadingAnchor, constant: 12),
            label.trailingAnchor.constraint(equalTo: trailingAnchor, constant: -12)
        ])

        alpha = 0
        isUserInteractionEnabled = false
    }

    required init?(coder: NSCoder) { fatalError() }

    func show(in view: UIView, message: String) {
        hideWorkItem?.cancel()
        label.text = message

        if superview == nil {
            view.addSubview(self)
            translatesAutoresizingMaskIntoConstraints = false
            NSLayoutConstraint.activate([
                centerXAnchor.constraint(equalTo: view.centerXAnchor),
                bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -14),
                widthAnchor.constraint(lessThanOrEqualTo: view.widthAnchor, multiplier: 0.92)
            ])
        }

        UIView.animate(withDuration: 0.2) { self.alpha = 1 }

        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            UIView.animate(withDuration: 0.25) { self.alpha = 0 }
        }
        hideWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + 2.3, execute: work)
    }
}

final class SegmentedPill: UIControl {
    private let stack = UIStackView()
    private var buttons: [UIButton] = []
    var items: [String] = [] { didSet { rebuild() } }
    var selectedIndex: Int = 0 { didSet { updateSelection() } }
    var onChange: ((Int) -> Void)?

    override init(frame: CGRect) {
        super.init(frame: frame)
        layer.cornerRadius = 12
        backgroundColor = .secondarySystemBackground

        stack.axis = .horizontal
        stack.distribution = .fillEqually
        stack.spacing = 6
        addSubview(stack)
        stack.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: topAnchor, constant: 6),
            stack.bottomAnchor.constraint(equalTo: bottomAnchor, constant: -6),
            stack.leadingAnchor.constraint(equalTo: leadingAnchor, constant: 6),
            stack.trailingAnchor.constraint(equalTo: trailingAnchor, constant: -6)
        ])
    }

    required init?(coder: NSCoder) { fatalError() }

    private func rebuild() {
        buttons.forEach { $0.removeFromSuperview() }
        buttons = []

        for (idx, title) in items.enumerated() {
            let b = UIButton(type: .system)
            b.setTitle(title, for: .normal)
            b.titleLabel?.font = UIFont.preferredFont(forTextStyle: .subheadline)
            b.layer.cornerRadius = 10
            b.tag = idx
            b.addTarget(self, action: #selector(tap(_:)), for: .touchUpInside)
            stack.addArrangedSubview(b)
            buttons.append(b)
        }
        updateSelection()
    }

    private func updateSelection() {
        for (idx, b) in buttons.enumerated() {
            let sel = idx == selectedIndex
            b.backgroundColor = sel ? .label : .clear
            b.setTitleColor(sel ? .systemBackground : .label, for: .normal)
        }
    }

    @objc private func tap(_ sender: UIButton) {
        selectedIndex = sender.tag
        sendActions(for: .valueChanged)
        onChange?(selectedIndex)
    }
}

