final class PortfolioViewController: UIViewController, UITableViewDataSource, UITableViewDelegate {
    private let table = UITableView(frame: .zero, style: .insetGrouped)
    private let header = PortfolioHeaderView()
    private var positions: [Position] = []
    private var cash: Decimal = 0
    private var equity: Decimal = 0
    private let toast = ToastView()

    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Portfolio"
        view.backgroundColor = .systemBackground

        table.dataSource = self
        table.delegate = self
        table.register(PositionCell.self, forCellReuseIdentifier: "PositionCell")
        table.rowHeight = 66
        table.tableHeaderView = header

        view.addSubview(table)
        table.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            table.topAnchor.constraint(equalTo: view.topAnchor),
            table.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            table.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            table.trailingAnchor.constraint(equalTo: view.trailingAnchor)
        ])

        navigationItem.rightBarButtonItem = UIBarButtonItem(title: "Trade", style: .done, target: self, action: #selector(openTrade))

        AppViewModel.shared.onPortfolio = { [weak self] p in
            guard let self else { return }
            self.positions = p.positions.sorted { $0.marketValue.doubleValue > $1.marketValue.doubleValue }
            self.cash = p.cash
            self.equity = p.totalEquity
            self.header.apply(cash: p.cash, equity: p.totalEquity, dayPnL: p.dayPnL)
            self.table.reloadData()
            self.layoutHeader()
        }

        AppViewModel.shared.onToast = { [weak self] msg in
            guard let self else { return }
            self.toast.show(in: self.view, message: msg)
        }

        AppViewModel.shared.start()
        layoutHeader()
    }

    override func viewDidLayoutSubviews() {
        super.viewDidLayoutSubviews()
        layoutHeader()
    }

    private func layoutHeader() {
        header.setNeedsLayout()
        header.layoutIfNeeded()
        let target = CGSize(width: view.bounds.width, height: UIView.layoutFittingCompressedSize.height)
        let size = header.systemLayoutSizeFitting(target, withHorizontalFittingPriority: .required, verticalFittingPriority: .fittingSizeLevel)
        if table.tableHeaderView?.frame.height != size.height {
            var f = header.frame
            f.size.height = size.height
            header.frame = f
            table.tableHeaderView = header
        }
    }

    @objc private func openTrade() {
        let vc = TradeViewController()
        navigationController?.pushViewController(vc, animated: true)
    }

    // UITableView
    func numberOfSections(in tableView: UITableView) -> Int { 1 }
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        max(positions.count, 1)
    }

    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        if positions.isEmpty {
            let cell = UITableViewCell(style: .subtitle, reuseIdentifier: nil)
            cell.textLabel?.text = "No positions yet"
            cell.detailTextLabel?.text = "Place a trade to start building your portfolio."
            cell.selectionStyle = .none
            return cell
        }
        let cell = tableView.dequeueReusableCell(withIdentifier: "PositionCell", for: indexPath) as! PositionCell
        cell.apply(positions[indexPath.row])
        return cell
    }

    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        guard !positions.isEmpty else { return }
        let pos = positions[indexPath.row]
        let vc = SymbolDetailViewController(symbol: pos.symbol)
        navigationController?.pushViewController(vc, animated: true)
    }
}

