final class TradeViewController: UIViewController {
    private let symbolField = UITextField()
    private let qtyField = UITextField()
    private let limitField = UITextField()

    private let sidePill = SegmentedPill()
    private let typePill = SegmentedPill()
    private let tifPill = SegmentedPill()

    private let quoteLabel = UILabel()
    private let actionButton = UIButton(type: .system)
    private let toast = ToastView()

    private var currentQuote: StockQuote?
    private var quoteTask: Task<Void, Never>?

    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Trade"
        view.backgroundColor = .systemBackground

        symbolField.placeholder = "Symbol (e.g. AAPL)"
        symbolField.autocapitalizationType = .allCharacters
        symbolField.autocorrectionType = .no
        symbolField.clearButtonMode = .whileEditing
        symbolField.borderStyle = .roundedRect
        symbolField.returnKeyType = .done
        symbolField.addTarget(self, action: #selector(symbolChanged), for: .editingChanged)
        symbolField.addTarget(self, action: #selector(symbolDone), for: .editingDidEndOnExit)

        qtyField.placeholder = "Quantity"
        qtyField.keyboardType = .decimalPad
        qtyField.borderStyle = .roundedRect

        limitField.placeholder = "Limit price (optional)"
        limitField.keyboardType = .decimalPad
        limitField.borderStyle = .roundedRect

        sidePill.items = ["Buy", "Sell"]
        typePill.items = ["Market", "Limit"]
        tifPill.items = ["Day", "GTC"]

        typePill.onChange = { [weak self] idx in
            self?.updateLimitVisibility(idx == 1)
        }

        quoteLabel.font = UIFont.preferredFont(forTextStyle: .footnote)
        quoteLabel.textColor = .secondaryLabel
        quoteLabel.numberOfLines = 0

        actionButton.setTitle("Review & Place Order", for: .normal)
        actionButton.titleLabel?.font = UIFont.systemFont(ofSize: 17, weight: .semibold)
        actionButton.configuration = .filled()
        actionButton.addTarget(self, action: #selector(placeTapped), for: .touchUpInside)

        let form = UIStackView(arrangedSubviews: [
            labeled("Symbol", symbolField),
            labeled("Side", sidePill),
            labeled("Order Type", typePill),
            labeled("Time in Force", tifPill),
            labeled("Quantity", qtyField),
            labeled("Limit Price", limitField),
            quoteLabel,
            actionButton
        ])
        form.axis = .vertical
        form.spacing = 12

        view.addSubview(form)
        form.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            form.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 16),
            form.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            form.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16)
        ])

        updateLimitVisibility(false)

        AppViewModel.shared.onToast = { [weak self] msg in
            guard let self else { return }
            self.toast.show(in: self.view, message: msg)
        }
    }

    private func labeled(_ title: String, _ control: UIView) -> UIView {
        let t = UILabel()
        t.text = title
        t.font = UIFont.preferredFont(forTextStyle: .caption1)
        t.textColor = .secondaryLabel

        let stack = UIStackView(arrangedSubviews: [t, control])
        stack.axis = .vertical
        stack.spacing = 6
        return stack
    }

    private func updateLimitVisibility(_ show: Bool) {
        limitField.isHidden = !show
    }

    @objc private func symbolChanged() {
        quoteTask?.cancel()
        let sym = symbolField.text?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        guard sym.count >= 1 else {
            quoteLabel.text = "Live quote will appear here."
            currentQuote = nil
            return
        }

        quoteTask = Task { [weak self] in
            try? await Task.sleep(nanoseconds: 350_000_000)
            guard let self, !Task.isCancelled else { return }
            await self.fetchQuote(sym)
        }
    }

    @objc private func symbolDone() {
        let sym = symbolField.text?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        if !sym.isEmpty {
            Task { [weak self] in await self?.fetchQuote(sym) }
        }
    }

    private func fetchQuote(_ symbol: String) async {
        do {
            let q = try await TradingService.shared.getQuote(symbol: symbol)
            currentQuote = q
            let mf = MoneyFormatter.shared
            quoteLabel.text = "\(q.symbol)  Last \(mf.money(q.last)) • Bid \(mf.money(q.bid)) • Ask \(mf.money(q.ask))"
        } catch {
            currentQuote = nil
            quoteLabel.text = "Quote unavailable for \(symbol)."
        }
    }

    @objc private func placeTapped() {
        view.endEditing(true)

        let symbol = (symbolField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let side: OrderSide = sidePill.selectedIndex == 0 ? .buy : .sell
        let type: OrderType = typePill.selectedIndex == 0 ? .market : .limit
        let tif: TimeInForce = tifPill.selectedIndex == 0 ? .day : .gtc

        let qtyText = (qtyField.text ?? "").replacingOccurrences(of: ",", with: ".")
        let limitText = (limitField.text ?? "").replacingOccurrences(of: ",", with: ".")

        let qty = Decimal(string: qtyText) ?? 0
        let limit = Decimal(string: limitText)

        let review = OrderReviewViewController(
            symbol: symbol,
            side: side,
            type: type,
            quantity: qty,
            limitPrice: (type == .limit ? limit : nil),
            tif: tif,
            quote: currentQuote
        )
        review.onConfirm = { [weak self] in
            guard let self else { return }
            Task {
                await AppViewModel.shared.submitOrder(
                    symbol: symbol,
                    side: side,
                    type: type,
                    quantity: qty,
                    limitPrice: (type == .limit ? limit : nil),
                    tif: tif
                )
            }
        }
        navigationController?.pushViewController(review, animated: true)
    }
}

final class OrderReviewViewController: UIViewController {
    let symbol: String
    let side: OrderSide
    let type: OrderType
    let quantity: Decimal
    let limitPrice: Decimal?
    let tif: TimeInForce
    let quote: StockQuote?

    var onConfirm: (() -> Void)?

    private let summary = UILabel()
    private let confirm = UIButton(type: .system)

    init(symbol: String, side: OrderSide, type: OrderType, quantity: Decimal, limitPrice: Decimal?, tif: TimeInForce, quote: StockQuote?) {
        self.symbol = symbol
        self.side = side
        self.type = type
        self.quantity = quantity
        self.limitPrice = limitPrice
        self.tif = tif
        self.quote = quote
        super.init(nibName: nil, bundle: nil)
    }

    required init?(coder: NSCoder) { fatalError() }

    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Review"
        view.backgroundColor = .systemBackground

        let mf = MoneyFormatter.shared
        let estPrice: Decimal? = {
            guard let quote else { return nil }
            switch side {
            case .buy: return quote.ask
            case .sell: return quote.bid
            }
        }()

        let notional: Decimal? = {
            let px: Decimal?
            if type == .limit { px = limitPrice }
            else { px = estPrice }
            guard let px else { return nil }
            return (px * quantity).rounded(2)
        }()

        summary.numberOfLines = 0
        summary.font = UIFont.preferredFont(forTextStyle: .body)

        var lines: [String] = []
        lines.append("\(side.rawValue.uppercased()) \(mf.qty(quantity)) \(symbol)")
        lines.append("Type: \(type.rawValue.uppercased())")
        lines.append("TIF: \(tif.rawValue.uppercased())")
        if type == .limit, let limitPrice {
            lines.append("Limit: \(mf.money(limitPrice))")
        }
        if let estPrice {
            lines.append("Est. price: \(mf.money(estPrice))")
        }
        if let notional {
            lines.append("Est. notional: \(mf.money(notional))")
        }
        if quote == nil {
            lines.append("Note: Live quote unavailable. Market order execution price may vary.")
        }
        summary.text = lines.joined(separator: "\n")

        confirm.setTitle("Place Order", for: .normal)
        confirm.titleLabel?.font = UIFont.systemFont(ofSize: 17, weight: .semibold)
        confirm.configuration = .filled()
        confirm.addTarget(self, action: #selector(confirmTapped), for: .touchUpInside)

        let stack = UIStackView(arrangedSubviews: [summary, confirm])
        stack.axis = .vertical
        stack.spacing = 18

        view.addSubview(stack)
        stack.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 18),
            stack.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            stack.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16)
        ])
    }

    @objc private func confirmTapped() {
        confirm.isEnabled = false
        onConfirm?()
        navigationController?.popToRootViewController(animated: true)
    }
}

final class SymbolDetailViewController: UIViewController {
    private let symbol: String
    private let quoteLabel = UILabel()
    private let toast = ToastView()

    init(symbol: String) {
        self.symbol = symbol
        super.init(nibName: nil, bundle: nil)
    }

    required init?(coder: NSCoder) { fatalError() }

    override func viewDidLoad() {
        super.viewDidLoad()
        title = symbol
        view.backgroundColor = .systemBackground

        quoteLabel.font = UIFont.preferredFont(forTextStyle: .body)
        quoteLabel.numberOfLines = 0
        quoteLabel.textColor = .label

        view.addSubview(quoteLabel)
        quoteLabel.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            quoteLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 16),
            quoteLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            quoteLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16)
        ])

        AppViewModel.shared.onToast = { [weak self] msg in
            guard let self else { return }
            self.toast.show(in: self.view, message: msg)
        }

        AppViewModel.shared.onQuotes = { [weak self] quotes in
            guard let self else { return }
            if let q = quotes[self.symbol] {
                let mf = MoneyFormatter.shared
                self.quoteLabel.text = "\(q.symbol)\nLast \(mf.money(q.last))\nBid \(mf.money(q.bid))\nAsk \(mf.money(q.ask))\nChange \(mf.money(q.change)) (\(mf.pct(q.changePercent)))"
            }
        }

        QuotesStream.shared.subscribe(symbols: [symbol])

        Task { [weak self] in
            guard let self else { return }
            do {
                let q = try await TradingService.shared.getQuote(symbol: self.symbol)
                let mf = MoneyFormatter.shared
                self.quoteLabel.text = "\(q.symbol)\nLast \(mf.money(q.last))\nBid \(mf.money(q.bid))\nAsk \(mf.money(q.ask))\nChange \(mf.money(q.change)) (\(mf.pct(q.changePercent)))"
            } catch {
                self.quoteLabel.text = "Quote unavailable."
            }
        }
    }
}

