final class SignInViewController: UIViewController {
    private let tokenField = UITextField()
    private let saveButton = UIButton(type: .system)
    private let hint = UILabel()
    private let toast = ToastView()

    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Sign In"
        view.backgroundColor = .systemBackground

        hint.text = "Enter an API access token to enable trading."
        hint.font = UIFont.preferredFont(forTextStyle: .footnote)
        hint.textColor = .secondaryLabel
        hint.numberOfLines = 0

        tokenField.placeholder = "Access token"
        tokenField.borderStyle = .roundedRect
        tokenField.autocorrectionType = .no
        tokenField.autocapitalizationType = .none
        tokenField.clearButtonMode = .whileEditing
        tokenField.textContentType = .password
        tokenField.isSecureTextEntry = true

        saveButton.setTitle("Continue", for: .normal)
        saveButton.configuration = .filled()
        saveButton.addTarget(self, action: #selector(saveTapped), for: .touchUpInside)

        let stack = UIStackView(arrangedSubviews: [hint, tokenField, saveButton])
        stack.axis = .vertical
        stack.spacing = 12

        view.addSubview(stack)
        stack.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 18),
            stack.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            stack.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16)
        ])
    }

    @objc private func saveTapped() {
        let token = (tokenField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
