        let nav = UINavigationController(rootViewController: PortfolioViewController())
        nav.navigationBar.prefersLargeTitles = true
        view.window?.rootViewController = nav
    }
}

// MARK: - App

@main
final class AppDelegate: UIResponder, UIApplicationDelegate {
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        true
    }

    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession,
                     options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
    }
}

final class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    var window: UIWindow?

    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let ws = scene as? UIWindowScene else { return }
        let w = UIWindow(windowScene: ws)

        let root: UIViewController
        if SessionManager.shared.accessToken == nil {
            root = UINavigationController(rootViewController: SignInViewController())
        } else {
            root = UINavigationController(rootViewController: PortfolioViewController())
        }
        (root as? UINavigationController)?.navigationBar.prefersLargeTitles = true

        w.rootViewController = root
        w.makeKeyAndVisible()
        window = w
    }

    func sceneDidEnterBackground(_ scene: UIScene) {
        AppViewModel.shared.stop()
    }

    func sceneWillEnterForeground(_ scene: UIScene) {
        AppViewModel.shared.start()
    }
}